<template>
  <div class="zyk_pay_steeing">
    <el-form
      v-if="processed == '未填'"
      ref="ruleForm"
      :model="form"
      class="demo-ruleForm"
      label-width="130px"
      :rules="rules"
    >
      <el-card class="box-card" shadow="never">
        <div slot="header" class="clearfix">
          <span>支付渠道信息</span>
        </div>
        <el-row :gutter="20">
          <el-col :span="12">
            <el-form-item label="費率類型" prop="fee_type">
              <el-select v-model="form.fee_type" style="width: 100%">
                <el-option
                  v-for="value in fee_type_options"
                  :key="value.code"
                  :label="value.name"
                  :value="value.code"
                />
              </el-select>
            </el-form-item>
          </el-col>
          <el-col v-if="form.fee_type" :span="12">
            <el-form-item label="經營類目" prop="wx_category">
              <el-select v-model="form.wx_category" placeholder="請選擇" style="width: 100%">
                <el-option
                  v-for="value in category_options"
                  :key="value.id"
                  :label="value.merchant_type_name"
                  :value="value.merchant_type_name"
                />
              </el-select>
            </el-form-item>
          </el-col>
          <el-col v-if="form.wx_category" :span="12">
            <el-form-item label="商戶種類" prop="mer_type">
              <el-select v-model="form.mer_type" placeholder="請選擇活動區域" style="width: 100%">
                <el-option
                  v-for="value in mer_type_options"
                  :key="value.code"
                  :label="value.name"
                  :value="value.code"
                />
              </el-select>
            </el-form-item>
          </el-col>
          <el-col :span="12">
            <el-form-item label="入駐模式" prop="model_type">
              <el-select v-model="form.model_type" placeholder="請選擇" style="width: 100%">
                <el-option
                  v-for="value in model_type_options"
                  :key="value.code"
                  :label="value.name"
                  :value="value.code"
                />
              </el-select>
            </el-form-item>
          </el-col>
          <el-col :span="12">
            <el-form-item label="地區" prop="select_regions_value">
              <el-cascader
                v-model="form.select_regions_value"
                style="width: 100%"
                placeholder="請選擇省市區"
                :options="area"
                @change="regionChange"
              />
            </el-form-item>
          </el-col>

          <!-- <el-col :span="12">
            <el-form-item label="微信小程序appid" prop="authorizer_appid">
              <el-input v-model="form.authorizer_appid" placeholder="" style="width: 100%" />
            </el-form-item>
          </el-col> -->
          <el-col :span="12">
            <el-form-item label="手續費扣費方式" prop="adapay_fee_mode">
              <el-select v-model="form.adapay_fee_mode" style="width: 100%">
                <el-option label="內扣" value="I" />
                <el-option label="外扣" value="O" />
              </el-select>
            </el-form-item>
          </el-col>
          <el-col :span="24">
            <el-form-item label="支付渠道">
              <el-checkbox-group v-model="channelList">
                <el-checkbox
                  v-for="channel in payChannel"
                  :key="channel.value"
                  :label="channel.value"
                >
                  {{ channel.name }}
                </el-checkbox>
              </el-checkbox-group>
              <div class="tip-msg">
                <p>微信小程序商城：勾選微信小程序支付。</p>
                <p>APP商城：勾選微信小程序支付、支付寶APP支付。</p>
                <p>H5商城：勾選微信小程序支付、微信公眾號支付、支付寶H5支付。</p>
                <p>PC端web商城：勾選微信公眾號支付、支付寶掃碼支付。</p>
              </div>
            </el-form-item>
          </el-col>
          <el-col :span="24">
            <el-form-item label="微信小程序AppID">
              <el-input
                v-model="wx_lite.appid"
                placeholder="請輸入微信小程序AppID"
                :disabled="channelList.indexOf('wx_lite') < 0"
                style="width: 220px"
              />
            </el-form-item>
          </el-col>
          <el-col :span="6">
            <el-form-item label="微信公眾號AppID">
              <el-input
                v-model="wx_pub.appid"
                placeholder="請輸入微信公眾號AppID"
                :disabled="channelList.indexOf('wx_pub') < 0"
                style="width: 220px"
              />
            </el-form-item>
          </el-col>
          <el-col :span="8">
            <el-form-item label="授權目錄">
              <el-input
                v-model="wx_pub.path"
                placeholder="請輸入授權目錄"
                :disabled="channelList.indexOf('wx_pub') < 0"
                style="width: 520px"
              />
            </el-form-item>
          </el-col>
        </el-row>
      </el-card>
      <el-form-item style="text-align: center; margin: 50px 0; margin-right: 130px">
        <el-button type="primary" @click="submitForm"> 提交審核 </el-button>
      </el-form-item>
    </el-form>
    <Result-cpn
      v-if="processed == '已填'"
      :current-status="currentStatus"
      @nextPage="nextPage"
      @processedHandle="processedHandle"
    />
    <check-box
      :visible="checkBoxConfig.visible"
      :message="checkBoxConfig.message"
      @checkBoxConfirmHandle="checkBoxConfirmHandle"
      @checkBoxVisibleHandle="checkBoxVisibleHandle"
    />
  </div>
</template>

<script>
import district from '@/common/district.json'
import ResultCpn from './cpn/result.vue'
import loadingBtn from '@/components/loading-btn'
import { MaxRules, requiredRules } from './tools'
import checkBox from './cpn/checkBox.vue'
export default {
  components: {
    ResultCpn,
    loadingBtn,
    checkBox
  },
  data() {
    return {
      allPro: '',
      allCity: [],
      allCountry: [],
      area: district,
      fee_type_options: [],
      mer_type_options: [],
      model_type_options: [],
      category_options: [],
      processed: '',
      currentStatus: {
        resultStatus: '',
        time: '',
        info: '',
        title: ''
      },
      checkBoxConfig: {
        visible: false,
        message: '請確認信息無誤！'
      },
      form: {
        fee_type: '', //費率類型
        wx_category: '', // 經營類目
        mer_type: '', // 商戶種類
        model_type: '', // 入駐模式
        province_code: '', //省份編碼
        city_code: '', //城市編碼
        district_code: '', //區縣編碼
        // authorizer_appid: '', //微信小程序appid
        select_regions_value: '',
        adapay_fee_mode: '', //小程序扣費方式
        add_value_list: {}
      },
      channelList: [],
      wx_lite: {
        appid: ''
      },
      wx_pub: {
        appid: '',
        path: ''
      },
      alipay: '',
      alipay_wap: '',
      alipay_qr: '',
      rules: {
        fee_type: requiredRules('費率類型', 'change'),
        model_type: requiredRules('入駐模式', 'change'),
        mer_type: requiredRules('商戶種類', 'change'),
        select_regions_value: requiredRules('地區', 'change'),
        // city_code:{ required: true, message: '請選擇', trigger: 'change' },
        // district_code:{ required: true, message: '請選擇', trigger: 'change' },
        wx_category: requiredRules('經營類目', 'change'),
        // authorizer_appid: [requiredRules('微信小程序appid'), MaxRules(40)],
        adapay_fee_mode: requiredRules('手續費扣費方式', 'change')
      },
      payChannel: [
        { name: '微信小程序', value: 'wx_lite' },
        { name: '微信公眾號', value: 'wx_pub' },
        { name: '支付寶APP', value: 'alipay' },
        { name: '支付寶H5', value: 'alipay_wap' },
        { name: '支付寶掃碼', value: 'alipay_qr' }
      ],
      isEcho: false // 是否回顯
    }
  },
  watch: {
    'form.fee_type'(val) {
      this.getCategoryOptions({
        fee_type: val
      })
      if (this.isEcho && this.form.wx_category) {
        return
      }
      this.form.wx_category = ''
      this.form.mer_type = ''
    },
    'form.wx_category'(val) {
      this.getMerTypeOptions({
        merchant_type_name: val
      })
      if (this.isEcho && this.form.mer_type) {
        this.isEcho = false
        return
      }
      this.form.mer_type = ''
    }
  },
  mounted() {
    this.getOptions()
    this.getStepHandle()
  },
  methods: {
    // 查詢開戶步驟
    async getStepHandle() {
      const { info } = await this.$api.adapay.getStep()
      const { MerchantResident } = info
      if (MerchantResident.length <= 0) {
        this.processed = '未填'
      } else {
        this.processed = '已填'
        this.currentStatus = {
          resultStatus: MerchantResident.status,
          time: MerchantResident.update_time,
          info: MerchantResident.wx_stat_msg,
          type: 'photo',
          title: '入駐'
        }
      }
    },
    nextPage() {
      this.$router.push('/applications/adapay/adapay_merchant/picture')
    },
    // 獲取options
    async getOptions() {
      const { fee_type, mer_type, model_type } = await this.$api.adapay.pay_options()
      this.fee_type_options = fee_type
      this.mer_type_options = mer_type
      this.model_type_options = model_type
    },
    // 獲取經營類目options
    async getCategoryOptions(obj) {
      const { list } = await this.$api.adapay.getCategoryList(obj)
      this.category_options = list
    },
    // 獲取商戶種類options
    async getMerTypeOptions(obj) {
      const { mer_type } = await this.$api.adapay.getMerTypeOption(obj)
      this.mer_type_options = mer_type
    },
    submitForm() {
      this.$refs['ruleForm'].validate(async (valid) => {
        if (valid) {
          if (this.channelList.indexOf('wx_lite') > -1 && this.wx_lite.appid == '') {
            return this.$message.error('微信小程序APPID不能為空')
          }
          if (this.channelList.indexOf('wx_pub') > -1) {
            if (this.wx_pub.appid == '') {
              return this.$message.error('微信公眾號APPID不能為空')
            } else if (this.wx_pub.path == '') {
              return this.$message.error('微信公眾號授權目錄不能為空')
            }
          }
          this.checkBoxVisibleHandle()
        } else {
          console.log('error submit!!')
          return false
        }
      })
    },
    regionChange(val) {
      console.log(val)
      this.form.province_code = val[0]
      this.form.city_code = val[1]
      this.form.district_code = val[2]
    },
    // 重新填寫
    async processedHandle() {
      const { info } = await this.$api.adapay.getStep()
      const { MerchantResident } = info
      this.isEcho = true
      this.form = { ...this.form, ...MerchantResident }
      this.form.select_regions_value = [
        this.form.province_code,
        this.form.city_code,
        this.form.district_code
      ]

      this.form.wx_category = MerchantResident.wx_category_name
      const { wx_lite, wx_pub, alipay, alipay_wap, alipay_qr } = JSON.parse(
        MerchantResident.add_value_list
      )
      if (wx_lite) {
        this.wx_lite = wx_lite
        this.channelList.push('wx_lite')
      }
      if (wx_pub) {
        this.wx_pub = wx_pub
        this.channelList.push('wx_pub')
      }
      if (alipay) {
        this.alipay = alipay
        this.channelList.push('alipay')
      }
      if (alipay_wap) {
        this.alipay_wap = alipay_wap
        this.channelList.push('alipay_wap')
      }
      if (alipay_qr) {
        this.alipay_qr = alipay_qr
        this.channelList.push('alipay_qr')
      }

      console.log(this.form)
      this.processed = '未填'
    },
    /* ----------------------------------checkBox start----------------------------------- */
    async checkBoxConfirmHandle() {
      try {
        let add_value_list = {}
        if (this.channelList.indexOf('wx_lite') > -1) {
          add_value_list['wx_lite'] = this.wx_lite
        }
        if (this.channelList.indexOf('wx_pub') > -1) {
          add_value_list['wx_pub'] = this.wx_pub
        }
        if (this.channelList.indexOf('alipay') > -1) {
          add_value_list['alipay'] = 'alipay'
        }
        if (this.channelList.indexOf('alipay_wap') > -1) {
          add_value_list['alipay_wap'] = 'alipay_wap'
        }
        if (this.channelList.indexOf('alipay_qr') > -1) {
          add_value_list['alipay_qr'] = 'alipay_qr'
        }
        let params = {
          ...this.form,
          add_value_list: JSON.stringify(add_value_list)
        }
        console.log(params)
        const { status } = await this.$api.adapay.submitPay(params)
        if (status) {
          this.processed = '已填'
          this.currentStatus = {
            resultStatus: 'pending',
            time: '',
            info: '',
            title: '入駐'
          }
        }
        this.checkBoxVisibleHandle()
      } catch (error) {
        console.error(error)
        // this.$refs['loadingBtn'].closeLoading()
        this.checkBoxVisibleHandle()
      }
    },
    checkBoxVisibleHandle() {
      this.checkBoxConfig.visible = !this.checkBoxConfig.visible
      // if (this.checkBoxConfig.visible) {
      //   this.$refs['loadingBtn'].closeLoading()
      // }
    }
    /* ----------------------------------checkBox  end ----------------------------------- */
  }
}
</script>

